package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultConstructorValue() throws Exception {
        // Use reflection to create instance with autoFlush = false
        CSVFormat format = CSVFormat.DEFAULT;
        boolean autoFlush = format.getAutoFlush();
        assertFalse(autoFlush);
    }

    @Test
    void testGetAutoFlush_WithAutoFlushTrue() throws Exception {
        // Create CSVFormat instance with autoFlush = true using reflection
        Field autoFlushField = CSVFormat.class.getDeclaredField("autoFlush");
        autoFlushField.setAccessible(true);

        // Clone DEFAULT and set autoFlush to true
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(true);
        assertTrue(format.getAutoFlush());

        // Also verify that reflection sees true
        assertTrue(autoFlushField.getBoolean(format));
    }

    @Test
    void testGetAutoFlush_WithAutoFlushFalse() throws Exception {
        // Create CSVFormat instance with autoFlush = false using withAutoFlush
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(false);
        assertFalse(format.getAutoFlush());
    }
}
